# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import Flask, request, redirect, url_for

app = Flask(__name__)

@app.route('/login', methods=['GET'])
def login():
    next_url = request.args.get('next')
    if not next_url:
        next_url = url_for('index')
    return f'Redirecting to {next_url}'

@app.route('/')
def index():
    return 'Welcome to the Index Page!'

if __name__ == '__main__':
    app.run(debug=True)